import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    next_node = None
    min_combined_distance = np.inf

    for node in unvisited_nodes:
        combined_distance = 0
        for truck_node in truck_nodes:
            combined_distance += distance_matrix[current_node][node] + distance_matrix[node][truck_node]
        if combined_distance < min_combined_distance:
            min_combined_distance = combined_distance
            next_node = node

    if next_node is None:
        next_node = depot_node

    return next_node
